/**
 * Type definitions for the Outseta embed script (window.Outseta).
 * These describe the client-side SDK loaded via script tag,
 * NOT the REST API types generated by Orval.
 */

export interface OutsetaUser {
  Uid: string;
  Email: string;
  FirstName?: string;
  LastName?: string;
  FullName?: string;
  Account?: {
    Uid?: string;
    Name?: string;
    CurrentSubscription?: {
      Uid?: string;
      Plan?: {
        Uid?: string;
        Name?: string;
      };
      SubscriptionAddOns?: Array<{
        AddOn?: {
          Uid?: string;
          Name?: string;
        };
      }>;
    };
  };
  [key: string]: unknown;
}

export interface AuthWidgetOptions {
  widgetMode?: "login" | "register" | "login|register";
  authenticationCallbackUrl?: string;
  mode?: "popup" | "embed";
  registrationDefaults?: string;
  [key: string]: unknown;
}

export interface ProfileWidgetOptions {
  tab?:
    | "profile"
    | "billing"
    | "planChange"
    | "purchaseAddOn"
    | "passwordChange"
    | "teamMembers";
  mode?: "popup" | "embed";
  stateProps?: Record<string, unknown>;
  [key: string]: unknown;
}

export interface OutsetaEmbed {
  setAccessToken: (token: string) => void;
  getAccessToken: () => Promise<string | null>;
  getUser: () => Promise<OutsetaUser>;
  logout: () => void;
  on: (event: string, callback: () => void) => void;
  auth: {
    open: (options?: AuthWidgetOptions) => void;
  };
  profile: {
    open: (options?: ProfileWidgetOptions) => void;
  };
}

declare global {
  interface Window {
    Outseta?: OutsetaEmbed;
  }
}
